# Layer 1: Essential Context

narr:Actor_GothamAcupuncture
  a narr:Actor ;
  dct:source narr:Sample_1 ;
  skos:note "High-end managed care acupuncture practice being formed on the Upper West Side of Manhattan by Peter Caron and Jordan Barber." ;
  skos:prefLabel "Gotham Acupuncture" .

narr:Actor_JordanBarber
  a narr:Actor ;
  dct:source narr:Sample_1 ;
  skos:note "Co-founder of Gotham Acupuncture; pelvic floor specialist; former president of state acupuncture association; operates multiple insurance-based practices on Long Island." ;
  skos:prefLabel "Jordan Barber" .

narr:Actor_PeterCaron
  a narr:Actor ;
  dct:source narr:Sample_1 ;
  skos:note "Co-founder of Gotham Acupuncture; former VP of ASNEY; acupuncturist specializing in post-stroke recovery, digestion, and anxiety/depression; co-author of forthcoming book." ;
  skos:prefLabel "Peter Caron" .

narr:Actor_Scarlet
  a narr:Actor ;
  dct:source narr:Sample_1 ;
  skos:note "aswritten.ai representative; conducted demo and discovery interview; 10 years of consulting in organizational and narrative strategy." ;
  skos:prefLabel "Scarlet" .

narr:Claim_DataSecurityPremium
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Peter believes 'more secure than HIPAA' local data management is a marketable premium feature for high-net-worth and celebrity clientele." ;
  narr:aboutNode narr:Actor_GothamAcupuncture ;
  narr:hasConvictionLevel narr:Conviction_Stake ;
  narr:supports narr:Narrative_2 .

narr:Claim_DoctorAuthorityLeverage
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Doctors already have authority and patient relationships; getting them to prescribe acupuncture care is more effective and ethical than direct patient solicitation." ;
  narr:aboutNode narr:Narrative_DoctorReferralPipeline ;
  narr:hasConvictionLevel narr:Conviction_Foundation ;
  narr:supports narr:Narrative_DoctorReferralPipeline .

narr:Claim_DoctorRelationshipMemory
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Peter identified using collective memory to track individual doctor relationship details across recorded calls, enabling personalized follow-up." ;
  narr:aboutNode narr:Actor_PeterCaron ;
  narr:hasConvictionLevel narr:Conviction_Stake ;
  narr:supports narr:Narrative_1 .

narr:Claim_DocumentsAreStale
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Scarlet: 'all documents are somewhat stale, and the goal is trying to figure out which part and which part is the direction.'" ;
  narr:aboutNode narr:Narrative_AswrittenValueProp ;
  narr:hasConvictionLevel narr:Conviction_Foundation ;
  narr:supports narr:Narrative_AswrittenValueProp .

narr:Claim_EnterprisePlanPricing
  a narr:Claim ;
  dct:created "2026-03-10"^^<http://www.w3.org/2001/XMLSchema#date> ;
  dct:source narr:Sample_1 ;
  skos:note "Features: single-tenant deployments, local LLM hosting, zero data retention, segmented access controls, infrastructure isolation and compliance features." ;
  skos:prefLabel "Enterprise Plan starts at $4,000/month and includes infrastructure isolation and compliance features" ;
  prov:wasAttributedTo narr:Actor_Scarlet ;
  narr:aboutNode narr:Narrative_PricingTierBoundary ;
  narr:hasConvictionLevel narr:Conviction_Foundation .

narr:Claim_FranchiseExpansion
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Franchise-like expansion is a possibility surfaced by Scarlet; Peter has not fully committed to the model but finds it directionally aligned." ;
  narr:aboutNode narr:Narrative_FranchiseLikeGrowth ;
  narr:hasConvictionLevel narr:Conviction_Notion ;
  narr:supports narr:Narrative_FranchiseLikeGrowth .

