  dct:source narr:Sample_1 ;
  skos:note "Scarlet explicitly frames enterprise tier as required to make the HIPAA-plus security claim defensible. Gotham may not need it on day one but transparency is warranted given clientele." ;
  skos:prefLabel "'More secure than HIPAA' is only a defensible claim with enterprise infrastructure isolation features" ;
  prov:wasAttributedTo narr:Actor_Scarlet ;
  narr:aboutNode narr:Narrative_HIPAAComplianceJustification ;
  narr:hasConvictionLevel narr:Conviction_Boulder .

narr:Claim_LocalLLM_HIPAA
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Peter asserts that running LLMs locally on a practice server, disconnected from the internet, sidesteps many HIPAA compliance issues and enables richer data use." ;
  narr:aboutNode narr:Actor_GothamAcupuncture ;
  narr:hasConvictionLevel narr:Conviction_Boulder ;
  narr:supports narr:Narrative_2 .

narr:Claim_NarrativeCharting
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Peter identifies narrative-based charting — rambling about a patient for 3–5 minutes and having AI produce a consistent chart format — as a high-value AI use case." ;
  narr:aboutNode narr:Actor_PeterCaron ;
  narr:hasConvictionLevel narr:Conviction_Boulder ;
  narr:supports narr:Narrative_1 .

narr:Claim_NichingIsBetterBranding
  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "'If you're like, I do everything, then you're kind of an expert in nothing as far as at least public perception, even if you happen to be an expert in everything, it's just bad branding.'" ;
  narr:aboutNode narr:Narrative_NichePositioning ;
  narr:hasConvictionLevel narr:Conviction_Foundation ;
  narr:supports narr:Narrative_NichePositioning .

