  skos:note "Generalist positioning actively lowers authority with specialist physicians; narrow specialty framing is required for credible doctor relationships." ;
  narr:aboutNode narr:Narrative_AuthorityPositioning ;
  narr:hasConvictionLevel narr:Conviction_Foundation ;
  narr:supports narr:Narrative_AuthorityPositioning .

