  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Peter expressed immediate, enthusiastic buy-in — seeing the usefulness of aswritten.ai immediately and stating he would love to use it." ;
  narr:aboutNode narr:Actor_PeterCaron ;
  narr:hasConvictionLevel narr:Conviction_Foundation ;
  narr:supports narr:Narrative_1 .

