  a narr:Claim ;
  dct:created "2026-03-10"^^<http://www.w3.org/2001/XMLSchema#date> ;
  dct:source narr:Sample_1 ;
  skos:note "Asserted by Scarlet in post-call review. Includes: unlimited team members, access to collective memory through Claude, organizational memory, knowledge extraction, content generation." ;
