  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "The moat is primarily time (5-year replication lag) via logistics and relationships, not proprietary IP or protocols." ;
  narr:aboutNode narr:Narrative_TimeAsTheMoat ;
