  a narr:Claim ;
  dct:source narr:Sample_1 ;
  skos:note "Scarlet identified that Gotham Acupuncture likely needs two separate worldviews: the organization as a business and the organization as a healthcare entity tracking patient treatments." ;
  narr:aboutNode narr:Actor_GothamAcupuncture ;
  narr:hasConvictionLevel narr:Conviction_Stake ;
  narr:supports narr:Narrative_1 .

